func SamplerActionCreateFn(dto *SamplerEntity, query workspaces.QueryDSL) (*SamplerEntity, *workspaces.IError) {
	// 1. Validate always
	if iError := SamplerValidator(dto, false); iError != nil {
		return nil, iError
	}
	// 1.5 Sanitize the content coming of the front-end
	SamplerEntityPreSanitize(dto, query)
	// 2. Append the necessary information about user, workspace
	SamplerEntityBeforeCreateAppend(dto, query)
	// 3. Append the necessary translations, even if english
	SamplerPolyglotCreateHandler(dto, query)
	// 3.5. Create other entities if we want select from them
	SamplerRelationContentCreate(dto, query)
	// 4. Create the entity
	var dbref *gorm.DB = nil
	if query.Tx == nil {
		dbref = workspaces.GetDbRef()
	} else {
		dbref = query.Tx
	}
	query.Tx = dbref
	err := dbref.Create(&dto).Error
	if err != nil {
		err := workspaces.GormErrorToIError(err)
		return dto, err
	}
	// 5. Create sub entities, objects or arrays, association to other entities
	SamplerAssociationCreate(dto, query)
	// 6. Fire the event into system
	event.MustFire(SAMPLER_EVENT_CREATED, event.M{
		"entity":    dto,
		"entityKey": workspaces.GetTypeString(&SamplerEntity{}),
		"target":    "workspace",
		"unqiueId":  query.WorkspaceId,
	})
	return dto, nil
}
