func SamplerActionBulkUpdate(
	query workspaces.QueryDSL, dto *workspaces.BulkRecordRequest[SamplerEntity]) (
	*workspaces.BulkRecordRequest[SamplerEntity], *workspaces.IError,
) {
	result := []*SamplerEntity{}
	err := workspaces.GetDbRef().Transaction(func(tx *gorm.DB) error {
		query.Tx = tx
		for _, record := range dto.Records {
			item, err := SamplerActionUpdate(query, record)
			if err != nil {
				return err
			} else {
				result = append(result, item)
			}
		}
		return nil
	})
	if err == nil {
		return dto, nil
	}
	return nil, err.(*workspaces.IError)
}
