func (x *SamplerEntity) FromCli(c *cli.Context) *SamplerEntity {
	return CastSamplerFromCli(c)
}
func CastSamplerFromCli(c *cli.Context) *SamplerEntity {
	template := &SamplerEntity{}
	if c.IsSet("uid") {
		template.UniqueId = c.String("uid")
	}
	if c.IsSet("pid") {
		x := c.String("pid")
		template.ParentId = &x
	}
	return template
}
