var AppendSamplerRouter = func(r *[]workspaces.Module3Action) {}

func GetSamplerModule3Actions() []workspaces.Module3Action {
	routes := []workspaces.Module3Action{
		SAMPLER_ACTION_QUERY,
		SAMPLER_ACTION_EXPORT,
		SAMPLER_ACTION_GET_ONE,
		SAMPLER_ACTION_POST_ONE,
		SAMPLER_ACTION_PATCH,
		SAMPLER_ACTION_PATCH_BULK,
		SAMPLER_ACTION_DELETE,
	}
	// Append user defined functions
	AppendSamplerRouter(&routes)
	return routes
}

